def prove_nfbidf(sys: System) -> Proof:
    """An equality theorem for effectively not free.  (Contributed by Mario
    Carneiro, 4-Oct-2016.) ~ df-nf changed.  (Revised by Wolf Lammen,
    18-Sep-2021.)
    """
    lb = ProofBuilder(sys, "nfbidf")
