    s3 = lb.ref("s3", "( ( φ ∨ ψ ) ↔ ( ¬ φ → ψ ) )", ref="df-or", note="df-or")
    s4 = lb.ref("s4", "( ∀ x ( φ ∨ ψ ) ↔ ∀ x ( ¬ φ → ψ ) )", s3, ref="albii", note="albii")
    s5 = lb.ref("s5", "( ( φ ∨ ∀ x ψ ) ↔ ( ¬ φ → ∀ x ψ ) )", ref="df-or", note="df-or")
    res = lb.ref("res", "( ∀ x ( φ ∨ ψ ) ↔ ( φ ∨ ∀ x ψ ) )", s2, s4, s5, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

