    s4 = lb.ref("s4", "( ∃ x ( φ ∧ ψ ) → ( ∃ x φ ∧ ψ ) )", s1, s3, ref="sylib", note="sylib")
    s5 = lb.ref("s5", "( ψ → ( φ → ( φ ∧ ψ ) ) )", ref="pm3.21", note="pm3.21")
    s6 = lb.ref("s6", "( ψ → ( ∃ x φ → ∃ x ( φ ∧ ψ ) ) )", h1, s5, ref="eximd", note="eximd")
    s7 = lb.ref("s7", "( ( ∃ x φ ∧ ψ ) → ∃ x ( φ ∧ ψ ) )", s6, ref="impcom", note="impcom")
    res = lb.ref("res", "( ∃ x ( φ ∧ ψ ) ↔ ( ∃ x φ ∧ ψ ) )", s4, s7, ref="impbii", note="impbii")
    return lb.build(res)

