    h4 = lb.hyp("dvelimhw.4", "( ¬ ∀ x x = y → ( y = z → ∀ x y = z ) )")
    s1 = lb.ref("s1", "F/ z ¬ ∀ x x = y", ref="nfv", note="nfv")
    s2 = lb.ref("s2", "( z = y ↔ y = z )", ref="equcom", note="equcom")
