    s4 = lb.ref("s4", "( ¬ ∀ x x = y → F/ x y = z )", s3, h4, ref="nf5d", note="nf5d")
    s5 = lb.ref("s5", "( ¬ ∀ x x = y → F/ x z = y )", s2, s4, ref="nfxfrd", note="nfxfrd")
    s6 = lb.ref("s6", "F/ x φ", h1, ref="nf5i", note="nf5i")
    s7 = lb.ref("s7", "( ¬ ∀ x x = y → F/ x φ )", s6, ref="a1i", note="a1i")
    s8 = lb.ref("s8", "( ¬ ∀ x x = y → F/ x ( z = y → φ ) )", s5, s7, ref="nfimd", note="nfimd")
    s9 = lb.ref("s9", "( ¬ ∀ x x = y → F/ x ∀ z ( z = y → φ ) )", s1, s8, ref="nfald", note="nfald")
    s10 = lb.ref("s10", "( ∀ z ( z = y → φ ) ↔ ψ )", h2, h3, ref="equsalhw", note="equsalhw")
    s11 = lb.ref("s11", "( F/ x ∀ z ( z = y → φ ) ↔ F/ x ψ )", s10, ref="nfbii", note="nfbii")
    s12 = lb.ref("s12", "( ¬ ∀ x x = y → F/ x ψ )", s9, s11, ref="sylib", note="sylib")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( ψ → ∀ x ψ ) )", s12, ref="nf5rd", note="nf5rd")
    return lb.build(res)

