    s7 = lb.ref("s7", "( ∀ y ∃ x ( φ → ψ ) ↔ ∀ y ( ∀ x φ → ψ ) )", s6, ref="albii", note="albii")
    s8 = lb.ref("s8", "F/ y φ", ref="nfv", note="nfv")
    s9 = lb.ref("s9", "F/ y ∀ x φ", s8, ref="nfal", note="nfal")
