    s11 = lb.ref("s11", "( ( ∀ x φ → ∀ y ψ ) ↔ ∀ y ∃ x ( φ → ψ ) )", s7, s10, ref="bitr2i", note="bitr2i")
    res = lb.ref("res", "( ∃ x ∀ y ( φ → ψ ) ↔ ∀ y ∃ x ( φ → ψ ) )", s2, s5, s11, ref="3bitri", note="3bitri")
