def prove_eean(sys: System) -> Proof:
    """Distribute existential quantifiers.  (Contributed by NM, 27-Oct-2010.)
    (Revised by Mario Carneiro, 6-Oct-2016.)
    """
    lb = ProofBuilder(sys, "eean")
    h1 = lb.hyp("eean.1", "F/ y φ")
    h2 = lb.hyp("eean.2", "F/ x ψ")
    s1 = lb.ref("s1", "( ∃ y ( φ ∧ ψ ) ↔ ( φ ∧ ∃ y ψ ) )", h1, ref="19.42", note="19.42")
    s2 = lb.ref("s2", "( ∃ x ∃ y ( φ ∧ ψ ) ↔ ∃ x ( φ ∧ ∃ y ψ ) )", s1, ref="exbii", note="exbii")
    s3 = lb.ref("s3", "F/ x ∃ y ψ", h2, ref="nfex", note="nfex")
    s4 = lb.ref("s4", "( ∃ x ( φ ∧ ∃ y ψ ) ↔ ( ∃ x φ ∧ ∃ y ψ ) )", s3, ref="19.41", note="19.41")
    res = lb.ref("res", "( ∃ x ∃ y ( φ ∧ ψ ) ↔ ( ∃ x φ ∧ ∃ y ψ ) )", s2, s4, ref="bitri", note="bitri")
    return lb.build(res)

def prove_eeanv(sys: System) -> Proof:
    """Distribute a pair of existential quantifiers over a conjunction.
    Combination of ~ 19.41v and ~ 19.42v .  For a version requiring fewer
    axioms but with additional disjoint variable conditions, see
    ~ exdistrv .  (Contributed by NM, 26-Jul-1995.)
    """
    lb = ProofBuilder(sys, "eeanv")
    s1 = lb.ref("s1", "F/ y φ", ref="nfv", note="nfv")
    s2 = lb.ref("s2", "F/ x ψ", ref="nfv", note="nfv")
    res = lb.ref("res", "( ∃ x ∃ y ( φ ∧ ψ ) ↔ ( ∃ x φ ∧ ∃ y ψ ) )", s1, s2, ref="eean", note="eean")
    return lb.build(res)

def prove_eeeanv(sys: System) -> Proof:
    """Distribute three existential quantifiers over a conjunction.
    (Contributed by NM, 26-Jul-1995.)  (Proof shortened by Andrew Salmon,
    25-May-2011.)  Reduce distinct variable restrictions.  (Revised by Wolf
    Lammen, 20-Jan-2018.)
    """
    lb = ProofBuilder(sys, "eeeanv")
    s1 = lb.ref("s1", "( ∃ x ∃ y ( φ ∧ ψ ) ↔ ( ∃ x φ ∧ ∃ y ψ ) )", ref="eeanv", note="eeanv")
    s2 = lb.ref("s2", "( ( ∃ x ∃ y ( φ ∧ ψ ) ∧ ∃ z χ ) ↔ ( ( ∃ x φ ∧ ∃ y ψ ) ∧ ∃ z χ ) )", s1, ref="anbi1i", note="anbi1i")
    s3 = lb.ref("s3", "( ( φ ∧ ψ ∧ χ ) ↔ ( ( φ ∧ ψ ) ∧ χ ) )", ref="df-3an", note="df-3an")
    s4 = lb.ref("s4", "( ∃ z ( φ ∧ ψ ∧ χ ) ↔ ∃ z ( ( φ ∧ ψ ) ∧ χ ) )", s3, ref="exbii", note="exbii")
    s5 = lb.ref("s5", "( ∃ z ( ( φ ∧ ψ ) ∧ χ ) ↔ ( ( φ ∧ ψ ) ∧ ∃ z χ ) )", ref="19.42v", note="19.42v")
    s6 = lb.ref("s6", "( ∃ z ( φ ∧ ψ ∧ χ ) ↔ ( ( φ ∧ ψ ) ∧ ∃ z χ ) )", s4, s5, ref="bitri", note="bitri")
    s7 = lb.ref("s7", "( ∃ x ∃ y ∃ z ( φ ∧ ψ ∧ χ ) ↔ ∃ x ∃ y ( ( φ ∧ ψ ) ∧ ∃ z χ ) )", s6, ref="2exbii", note="2exbii")
    s8 = lb.ref("s8", "F/ y χ", ref="nfv", note="nfv")
    s9 = lb.ref("s9", "F/ y ∃ z χ", s8, ref="nfex", note="nfex")
    s10 = lb.ref("s10", "( ∃ y ( ( φ ∧ ψ ) ∧ ∃ z χ ) ↔ ( ∃ y ( φ ∧ ψ ) ∧ ∃ z χ ) )", s9, ref="19.41", note="19.41")
    s11 = lb.ref("s11", "( ∃ x ∃ y ( ( φ ∧ ψ ) ∧ ∃ z χ ) ↔ ∃ x ( ∃ y ( φ ∧ ψ ) ∧ ∃ z χ ) )", s10, ref="exbii", note="exbii")
    s12 = lb.ref("s12", "F/ x χ", ref="nfv", note="nfv")
    s13 = lb.ref("s13", "F/ x ∃ z χ", s12, ref="nfex", note="nfex")
    s14 = lb.ref("s14", "( ∃ x ( ∃ y ( φ ∧ ψ ) ∧ ∃ z χ ) ↔ ( ∃ x ∃ y ( φ ∧ ψ ) ∧ ∃ z χ ) )", s13, ref="19.41", note="19.41")
    s15 = lb.ref("s15", "( ∃ x ∃ y ∃ z ( φ ∧ ψ ∧ χ ) ↔ ( ∃ x ∃ y ( φ ∧ ψ ) ∧ ∃ z χ ) )", s7, s11, s14, ref="3bitri", note="3bitri")
    s16 = lb.ref("s16", "( ( ∃ x φ ∧ ∃ y ψ ∧ ∃ z χ ) ↔ ( ( ∃ x φ ∧ ∃ y ψ ) ∧ ∃ z χ ) )", ref="df-3an", note="df-3an")
    res = lb.ref("res", "( ∃ x ∃ y ∃ z ( φ ∧ ψ ∧ χ ) ↔ ( ∃ x φ ∧ ∃ y ψ ∧ ∃ z χ ) )", s2, s15, s16, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

def prove_ee4anv(sys: System) -> Proof:
    """Distribute two pairs of existential quantifiers over a conjunction.  For
    a version requiring fewer axioms but with additional disjoint variable
    conditions, see ~ 4exdistrv .  (Contributed by NM, 31-Jul-1995.)  Remove
    disjoint variable conditions on ` y , z ` and ` x , w ` .  (Revised by
    Eric Schmidt, 26-Oct-2025.)
    """
    lb = ProofBuilder(sys, "ee4anv")
    s1 = lb.ref("s1", "( ∃ y ∃ z ∃ w ( φ ∧ ψ ) ↔ ∃ z ∃ y ∃ w ( φ ∧ ψ ) )", ref="excom", note="excom")
    s2 = lb.ref("s2", "( ∃ x ∃ y ∃ z ∃ w ( φ ∧ ψ ) ↔ ∃ x ∃ z ∃ y ∃ w ( φ ∧ ψ ) )", s1, ref="exbii", note="exbii")
    s3 = lb.ref("s3", "( ∃ y ∃ w ( φ ∧ ψ ) ↔ ( ∃ y φ ∧ ∃ w ψ ) )", ref="eeanv", note="eeanv")
    s4 = lb.ref("s4", "( ∃ x ∃ z ∃ y ∃ w ( φ ∧ ψ ) ↔ ∃ x ∃ z ( ∃ y φ ∧ ∃ w ψ ) )", s3, ref="2exbii", note="2exbii")
    s5 = lb.ref("s5", "F/ z φ", ref="nfv", note="nfv")
    s6 = lb.ref("s6", "F/ z ∃ y φ", s5, ref="nfex", note="nfex")
    s7 = lb.ref("s7", "F/ x ψ", ref="nfv", note="nfv")
    s8 = lb.ref("s8", "F/ x ∃ w ψ", s7, ref="nfex", note="nfex")
    s9 = lb.ref("s9", "( ∃ x ∃ z ( ∃ y φ ∧ ∃ w ψ ) ↔ ( ∃ x ∃ y φ ∧ ∃ z ∃ w ψ ) )", s6, s8, ref="eean", note="eean")
    res = lb.ref("res", "( ∃ x ∃ y ∃ z ∃ w ( φ ∧ ψ ) ↔ ( ∃ x ∃ y φ ∧ ∃ z ∃ w ψ ) )", s2, s4, s9, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_ee4anvOLD(sys: System) -> Proof:
    """Obsolete version of ~ ee4anv as of 26-Oct-2025.  (Contributed by NM,
    31-Jul-1995.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "ee4anvOLD")
    s1 = lb.ref("s1", "( ∃ y ∃ z ∃ w ( φ ∧ ψ ) ↔ ∃ z ∃ y ∃ w ( φ ∧ ψ ) )", ref="excom", note="excom")
    s2 = lb.ref("s2", "( ∃ x ∃ y ∃ z ∃ w ( φ ∧ ψ ) ↔ ∃ x ∃ z ∃ y ∃ w ( φ ∧ ψ ) )", s1, ref="exbii", note="exbii")
    s3 = lb.ref("s3", "( ∃ y ∃ w ( φ ∧ ψ ) ↔ ( ∃ y φ ∧ ∃ w ψ ) )", ref="eeanv", note="eeanv")
    s4 = lb.ref("s4", "( ∃ x ∃ z ∃ y ∃ w ( φ ∧ ψ ) ↔ ∃ x ∃ z ( ∃ y φ ∧ ∃ w ψ ) )", s3, ref="2exbii", note="2exbii")
    s5 = lb.ref("s5", "( ∃ x ∃ z ( ∃ y φ ∧ ∃ w ψ ) ↔ ( ∃ x ∃ y φ ∧ ∃ z ∃ w ψ ) )", ref="eeanv", note="eeanv")
    res = lb.ref("res", "( ∃ x ∃ y ∃ z ∃ w ( φ ∧ ψ ) ↔ ( ∃ x ∃ y φ ∧ ∃ z ∃ w ψ ) )", s2, s4, s5, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_sb8v(sys: System) -> Proof:
    """Substitution of variable in universal quantifier.  Version of ~ sb8f
    with a disjoint variable condition replacing the nonfree hypothesis
    ` F/ y ph ` , not requiring ~ ax-12 .  (Contributed by SN,
    5-Dec-2024.)
    """
    lb = ProofBuilder(sys, "sb8v")
    s1 = lb.ref("s1", "( [ y / x ] φ ↔ ∀ x ( x = y → φ ) )", ref="sb6", note="sb6")
    s2 = lb.ref("s2", "( ∀ y [ y / x ] φ ↔ ∀ y ∀ x ( x = y → φ ) )", s1, ref="albii", note="albii")
    s3 = lb.ref("s3", "( ∀ y ∀ x ( x = y → φ ) ↔ ∀ x ∀ y ( x = y → φ ) )", ref="alcom", note="alcom")
    s4 = lb.ref("s4", "( x = y ↔ y = x )", ref="equcom", note="equcom")
    s5 = lb.ref("s5", "( ( x = y → φ ) ↔ ( y = x → φ ) )", s4, ref="imbi1i", note="imbi1i")
    s6 = lb.ref("s6", "( ∀ y ( x = y → φ ) ↔ ∀ y ( y = x → φ ) )", s5, ref="albii", note="albii")
    s7 = lb.ref("s7", "( ∀ y ( y = x → φ ) ↔ φ )", ref="equsv", note="equsv")
    s8 = lb.ref("s8", "( ∀ y ( x = y → φ ) ↔ φ )", s6, s7, ref="bitri", note="bitri")
    s9 = lb.ref("s9", "( ∀ x ∀ y ( x = y → φ ) ↔ ∀ x φ )", s8, ref="albii", note="albii")
    res = lb.ref("res", "( ∀ x φ ↔ ∀ y [ y / x ] φ )", s2, s3, s9, ref="3bitrri", note="3bitrri")
    return lb.build(res)

def prove_sb8f(sys: System) -> Proof:
    """Substitution of variable in universal quantifier.  Version of ~ sb8 with
    a disjoint variable condition, not requiring ~ ax-10 or ~ ax-13 .
    (Contributed by NM, 16-May-1993.)  (Revised by Wolf Lammen,
    19-Jan-2023.)  Avoid ~ ax-10 .  (Revised by SN, 5-Dec-2024.)
    """
    lb = ProofBuilder(sys, "sb8f")
    h1 = lb.hyp("sb8f.nf", "F/ y φ")
    s1 = lb.ref("s1", "( [ y / x ] φ ↔ ∀ x ( x = y → φ ) )", ref="sb6", note="sb6")
    s2 = lb.ref("s2", "( ∀ y [ y / x ] φ ↔ ∀ y ∀ x ( x = y → φ ) )", s1, ref="albii", note="albii")
    s3 = lb.ref("s3", "( ∀ y ∀ x ( x = y → φ ) ↔ ∀ x ∀ y ( x = y → φ ) )", ref="alcom", note="alcom")
    s4 = lb.ref("s4", "( [ x / y ] φ ↔ ∀ y ( y = x → φ ) )", ref="sb6", note="sb6")
    s5 = lb.ref("s5", "( [ x / y ] φ ↔ φ )", h1, ref="sbf", note="sbf")
    s6 = lb.ref("s6", "( y = x ↔ x = y )", ref="equcom", note="equcom")
    s7 = lb.ref("s7", "( ( y = x → φ ) ↔ ( x = y → φ ) )", s6, ref="imbi1i", note="imbi1i")
    s8 = lb.ref("s8", "( ∀ y ( y = x → φ ) ↔ ∀ y ( x = y → φ ) )", s7, ref="albii", note="albii")
    s9 = lb.ref("s9", "( ∀ y ( x = y → φ ) ↔ φ )", s4, s5, s8, ref="3bitr3ri", note="3bitr3ri")
    s10 = lb.ref("s10", "( ∀ x ∀ y ( x = y → φ ) ↔ ∀ x φ )", s9, ref="albii", note="albii")
    res = lb.ref("res", "( ∀ x φ ↔ ∀ y [ y / x ] φ )", s2, s3, s10, ref="3bitrri", note="3bitrri")
    return lb.build(res)

def prove_sb8ef(sys: System) -> Proof:
    """Substitution of variable in existential quantifier.  Version of ~ sb8e
    with a disjoint variable condition, not requiring ~ ax-13 .
    (Contributed by NM, 12-Aug-1993.)  (Revised by Wolf Lammen,
    19-Jan-2023.)
    """
    lb = ProofBuilder(sys, "sb8ef")
    h1 = lb.hyp("sb8f.nf", "F/ y φ")
    s1 = lb.ref("s1", "F/ x [ y / x ] φ", ref="nfs1v", note="nfs1v")
    s2 = lb.ref("s2", "( x = y → ( φ ↔ [ y / x ] φ ) )", ref="sbequ12", note="sbequ12")
    res = lb.ref("res", "( ∃ x φ ↔ ∃ y [ y / x ] φ )", h1, s1, s2, ref="cbvexv1", note="cbvexv1")
    return lb.build(res)

def prove_2sb8ef(sys: System) -> Proof:
    """An equivalent expression for double existence.  Version of ~ 2sb8e with
    more disjoint variable conditions, not requiring ~ ax-13 .  (Contributed
    by Wolf Lammen, 28-Jan-2023.)
    """
    lb = ProofBuilder(sys, "2sb8ef")
    h1 = lb.hyp("2sb8ef.1", "F/ w φ")
    h2 = lb.hyp("2sb8ef.2", "F/ z φ")
    s1 = lb.ref("s1", "( ∃ y φ ↔ ∃ w [ w / y ] φ )", h1, ref="sb8ef", note="sb8ef")
    s2 = lb.ref("s2", "( ∃ x ∃ y φ ↔ ∃ x ∃ w [ w / y ] φ )", s1, ref="exbii", note="exbii")
    s3 = lb.ref("s3", "( ∃ x ∃ w [ w / y ] φ ↔ ∃ w ∃ x [ w / y ] φ )", ref="excom", note="excom")
    s4 = lb.ref("s4", "( ∃ x ∃ y φ ↔ ∃ w ∃ x [ w / y ] φ )", s2, s3, ref="bitri", note="bitri")
    s5 = lb.ref("s5", "F/ z [ w / y ] φ", h2, ref="nfsbv", note="nfsbv")
    s6 = lb.ref("s6", "( ∃ x [ w / y ] φ ↔ ∃ z [ z / x ] [ w / y ] φ )", s5, ref="sb8ef", note="sb8ef")
    s7 = lb.ref("s7", "( ∃ w ∃ x [ w / y ] φ ↔ ∃ w ∃ z [ z / x ] [ w / y ] φ )", s6, ref="exbii", note="exbii")
    s8 = lb.ref("s8", "( ∃ w ∃ z [ z / x ] [ w / y ] φ ↔ ∃ z ∃ w [ z / x ] [ w / y ] φ )", ref="excom", note="excom")
    res = lb.ref("res", "( ∃ x ∃ y φ ↔ ∃ z ∃ w [ z / x ] [ w / y ] φ )", s4, s7, s8, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_sb6rfv(sys: System) -> Proof:
    """Reversed substitution.  Version of ~ sb6rf requiring disjoint variables,
    but fewer axioms.  (Contributed by NM, 1-Aug-1993.)  (Revised by Wolf
    Lammen, 7-Feb-2023.)
    """
    lb = ProofBuilder(sys, "sb6rfv")
    h1 = lb.hyp("sb6rfv.nf", "F/ y φ")
    s1 = lb.ref("s1", "( y = x → ( [ y / x ] φ ↔ φ ) )", ref="sbequ12r", note="sbequ12r")
    s2 = lb.ref("s2", "( ∀ y ( y = x → [ y / x ] φ ) ↔ φ )", h1, s1, ref="equsalv", note="equsalv")
    res = lb.ref("res", "( φ ↔ ∀ y ( y = x → [ y / x ] φ ) )", s2, ref="bicomi", note="bicomi")
    return lb.build(res)

def prove_sbnf2(sys: System) -> Proof:
    """Two ways of expressing " ` x ` is (effectively) not free in ` ph ` ".
    (Contributed by G&eacute;rard Lang, 14-Nov-2013.)  (Revised by Mario
    Carneiro, 6-Oct-2016.)  (Proof shortened by Wolf Lammen, 22-Sep-2018.)
    Avoid ~ ax-13 .  (Revised by Wolf Lammen, 30-Jan-2023.)
    """
    lb = ProofBuilder(sys, "sbnf2")
    s1 = lb.ref("s1", "F/ y φ", ref="nfv", note="nfv")
    s2 = lb.ref("s2", "( ∃ x φ ↔ ∃ y [ y / x ] φ )", s1, ref="sb8ef", note="sb8ef")
    s3 = lb.ref("s3", "( ∀ x φ ↔ ∀ z [ z / x ] φ )", ref="sb8v", note="sb8v")
    s4 = lb.ref("s4", "( ( ∃ x φ → ∀ x φ ) ↔ ( ∃ y [ y / x ] φ → ∀ z [ z / x ] φ ) )", s2, s3, ref="imbi12i", note="imbi12i")
    s5 = lb.ref("s5", "( F/ x φ ↔ ( ∃ x φ → ∀ x φ ) )", ref="df-nf", note="df-nf")
    s6 = lb.ref("s6", "( ∀ y ∀ z ( [ y / x ] φ → [ z / x ] φ ) ↔ ( ∃ y [ y / x ] φ → ∀ z [ z / x ] φ ) )", ref="pm11.53v", note="pm11.53v")
    s7 = lb.ref("s7", "( F/ x φ ↔ ∀ y ∀ z ( [ y / x ] φ → [ z / x ] φ ) )", s4, s5, s6, ref="3bitr4i", note="3bitr4i")
    s8 = lb.ref("s8", "F/ z φ", ref="nfv", note="nfv")
    s9 = lb.ref("s9", "( ∃ x φ ↔ ∃ z [ z / x ] φ )", s8, ref="sb8ef", note="sb8ef")
    s10 = lb.ref("s10", "( ∀ x φ ↔ ∀ y [ y / x ] φ )", ref="sb8v", note="sb8v")
    s11 = lb.ref("s11", "( ( ∃ x φ → ∀ x φ ) ↔ ( ∃ z [ z / x ] φ → ∀ y [ y / x ] φ ) )", s9, s10, ref="imbi12i", note="imbi12i")
    s12 = lb.ref("s12", "( F/ x φ ↔ ( ∃ x φ → ∀ x φ ) )", ref="df-nf", note="df-nf")
    s13 = lb.ref("s13", "( ∀ z ∀ y ( [ z / x ] φ → [ y / x ] φ ) ↔ ( ∃ z [ z / x ] φ → ∀ y [ y / x ] φ ) )", ref="pm11.53v", note="pm11.53v")
    s14 = lb.ref("s14", "( F/ x φ ↔ ∀ z ∀ y ( [ z / x ] φ → [ y / x ] φ ) )", s11, s12, s13, ref="3bitr4i", note="3bitr4i")
    s15 = lb.ref("s15", "( ∀ z ∀ y ( [ z / x ] φ → [ y / x ] φ ) ↔ ∀ y ∀ z ( [ z / x ] φ → [ y / x ] φ ) )", ref="alcom", note="alcom")
    s16 = lb.ref("s16", "( F/ x φ ↔ ∀ y ∀ z ( [ z / x ] φ → [ y / x ] φ ) )", s14, s15, ref="bitri", note="bitri")
    s17 = lb.ref("s17", "( ( F/ x φ ∧ F/ x φ ) ↔ ( ∀ y ∀ z ( [ y / x ] φ → [ z / x ] φ ) ∧ ∀ y ∀ z ( [ z / x ] φ → [ y / x ] φ ) ) )", s7, s16, ref="anbi12i", note="anbi12i")
    s18 = lb.ref("s18", "( F/ x φ ↔ ( F/ x φ ∧ F/ x φ ) )", ref="pm4.24", note="pm4.24")
    s19 = lb.ref("s19", "( ∀ y ∀ z ( [ y / x ] φ ↔ [ z / x ] φ ) ↔ ( ∀ y ∀ z ( [ y / x ] φ → [ z / x ] φ ) ∧ ∀ y ∀ z ( [ z / x ] φ → [ y / x ] φ ) ) )", ref="2albiim", note="2albiim")
    res = lb.ref("res", "( F/ x φ ↔ ∀ y ∀ z ( [ y / x ] φ ↔ [ z / x ] φ ) )", s17, s18, s19, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)


